create extension if not exists pgcrypto;
create table public.workspaces(id uuid primary key default gen_random_uuid(),owner_id uuid not null unique references auth.users(id) on delete cascade,name text not null default 'Koalafrog HQ',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.workspace_records(id text not null,workspace_id uuid not null references public.workspaces(id) on delete cascade,owner_id uuid not null references auth.users(id) on delete cascade,entity_type text not null,data jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),primary key(workspace_id,entity_type,id),check(length(id)>0),check(jsonb_typeof(data)='object'));
create index workspace_records_owner_type on public.workspace_records(owner_id,entity_type);
create table public.migration_runs(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,owner_id uuid not null references auth.users(id) on delete cascade,source_version text not null,state text not null,stage text not null default 'validation',entity_counts jsonb not null default '{}',imported_counts jsonb not null default '{}',skipped_counts jsonb not null default '{}',warnings jsonb not null default '[]',errors jsonb not null default '[]',reconciliation jsonb not null default '{}',created_at timestamptz not null default now(),completed_at timestamptz);
create table public.document_objects(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,owner_id uuid not null references auth.users(id) on delete cascade,document_record_id text not null,bucket text not null default 'compliance-documents',object_path text not null unique,original_file_name text not null,mime_type text not null,size bigint not null check(size>=0),checksum text,uploaded_at timestamptz not null default now(),replaced_by uuid references public.document_objects(id));
alter table public.workspaces enable row level security;alter table public.workspace_records enable row level security;alter table public.migration_runs enable row level security;alter table public.document_objects enable row level security;
create policy workspace_owner_all on public.workspaces for all using(owner_id=auth.uid()) with check(owner_id=auth.uid());
create policy records_owner_select on public.workspace_records for select using(owner_id=auth.uid() and workspace_id in(select id from public.workspaces where owner_id=auth.uid()));
create policy records_owner_insert on public.workspace_records for insert with check(owner_id=auth.uid() and workspace_id in(select id from public.workspaces where owner_id=auth.uid()));
create policy records_owner_update on public.workspace_records for update using(owner_id=auth.uid()) with check(owner_id=auth.uid());
create policy migration_owner_all on public.migration_runs for all using(owner_id=auth.uid()) with check(owner_id=auth.uid());
create policy documents_owner_all on public.document_objects for all using(owner_id=auth.uid()) with check(owner_id=auth.uid());
insert into storage.buckets(id,name,public,file_size_limit) values('compliance-documents','compliance-documents',false,52428800) on conflict(id) do update set public=false;
create policy storage_owner_read on storage.objects for select to authenticated using(bucket_id='compliance-documents' and (storage.foldername(name))[1]=auth.uid()::text);
create policy storage_owner_insert on storage.objects for insert to authenticated with check(bucket_id='compliance-documents' and (storage.foldername(name))[1]=auth.uid()::text);
create policy storage_owner_delete on storage.objects for delete to authenticated using(bucket_id='compliance-documents' and (storage.foldername(name))[1]=auth.uid()::text);
revoke all on public.workspaces,public.workspace_records,public.migration_runs,public.document_objects from anon;
